const root = $input.first().json;
const payload = root.payload || {};
const contact = payload.contact || {};
const locale = contact.preferred_language === 'en' ? 'en' : 'es';
const reviewUrl = $env.GOOGLE_REVIEWS_URL || 'https://share.google/CZL2ZHAKEqVgdIEuJ';
const crmBase = ($env.CRM_BASE_URL || 'https://www.clickin360.com').replace(/\/$/, '');
const feedbackUrl = contact.feedback_token ? `${crmBase}/feedback/${contact.feedback_token}` : null;
return [{ json: { contact, locale, reviewUrl, feedbackUrl, contactEmail: contact.email, firstName: contact.first_name || 'there', contactId: contact.id, optOut: contact.review_request_opt_out === true } }];

const d = $input.first().json;
const isEn = d.locale === 'en';
const subject = isEn ? `Would you leave us a Google review, ${d.firstName}?` : `¿Nos dejas una reseña en Google, ${d.firstName}?`;
const text = isEn
  ? `Hi ${d.firstName},

Thank you for completing onboarding with ClickIn 360. If you had a good experience, a quick Google review would mean a lot:

${d.reviewUrl}

It only takes a minute. Thank you!${d.feedbackUrl ? `

You can also share private feedback here: ${d.feedbackUrl}` : ''}`
  : `Hola ${d.firstName},

Gracias por completar la incorporación con ClickIn 360. Si tuviste una buena experiencia, nos ayudaría mucho una reseña breve en Google:

${d.reviewUrl}

Solo toma un minuto. ¡Gracias!${d.feedbackUrl ? `

También puedes compartir comentarios privados aquí: ${d.feedbackUrl}` : ''}`;
return [{ json: { ...d, subject, text, toEmail: d.contactEmail } }];
